exercises.solution_code:
#include <iostream>
#include <string>

int main()
{
    using namespace std::string_literals;

    std::string name {};
    int level {};
    std::cin >> name >> level;

    const std::string base { "Hello, "s };

    std::string greeting { base };
    greeting += name;

    if (level == 1)
        greeting += "!";
    else if (level == 2)
        greeting += "!!";
    else if (level == 3)
        greeting += "!!!";
    else if (level == 4)
        greeting += "!!!!";
    else if (level == 5)
        greeting += "!!!!!";

    std::cout << "Greeting: " << greeting << "\n";
    std::cout << "Length: " << greeting.size() << "\n";

    return 0;
}
